async (page) => {
  const click = async (x, y) => {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x, y});
    await page.waitForTimeout(2500);
  };

  // Keep clicking toward Blacksmith
  for (let i = 0; i < 4; i++) {
    await click(1200, 650);
    const s = await page.evaluate(() => {
      const s = window.__latestGameState;
      const bs = s.nearby_entities.find(e => e.name === 'Blacksmith');
      return { x: s.player_position.x, y: s.player_position.y, bsDist: bs ? bs.distance : 99, bsOn: bs ? bs.on_screen : false, bsCx: bs ? bs.click_x : null, bsCy: bs ? bs.click_y : null };
    });
    console.log(`Step ${i}: pos(${s.x},${s.y}) dist=${s.bsDist} on=${s.bsOn} cx=${s.bsCx} cy=${s.bsCy}`);
    if (s.bsOn && s.bsCx) {
      // Blacksmith on screen - click it!
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, {x: s.bsCx, y: s.bsCy || 360});
      break;
    }
    if (s.bsDist <= 3) break;
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    const bs = s.nearby_entities.find(e => e.name === 'Blacksmith');
    return { pos: s.player_position, bsDist: bs ? bs.distance : 99, bsOn: bs ? bs.on_screen : false, bsCx: bs ? bs.click_x : null, bsCy: bs ? bs.click_y : null };
  });
  return JSON.stringify(finalState);
}

