async (page) => {
  // Try to find the Blacksmith entity and interact via game API
  const info = await page.evaluate(() => {
    const bsEntity = window.game.entities.get('1-44123474');
    if (!bsEntity) return JSON.stringify({ error: 'Entity not found' });

    // Get the NPC's screen position using the game's camera
    const camera = window.game.camera;
    const gridSize = window.game.map.getGridSize ? window.game.map.getGridSize() : 16;
    const zoom = camera.zoomFactor || window.game.renderer.camera?.zoomFactor || 3;

    // Try to get screen coords
    const screenX = (bsEntity.x * gridSize - camera.x) * zoom;
    const screenY = (bsEntity.y * gridSize - camera.y) * zoom;

    return JSON.stringify({
      entity_x: bsEntity.x,
      entity_y: bsEntity.y,
      camera_x: camera.x,
      camera_y: camera.y,
      gridSize,
      zoom,
      screenX,
      screenY,
      cameraWidth: camera.width,
      cameraHeight: camera.height
    });
  });
  return info;
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Keep walking east toward unnamed mobs
  for (let i = 0; i < 5; i++) {
    await click(1200, 360);
    await page.waitForTimeout(2500);

    const pos = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const cam = window.game.camera;
      const closest = gs.nearby_entities.filter(e => e.type === 3 && (!e.name || e.name === ''))[0];
      return {
        player: gs.player_position,
        hp: gs.player_stats.hp + '/' + gs.player_stats.max_hp,
        closest_unnamed: closest ? {
          x: closest.x, y: closest.y, dist: closest.distance,
          sx: Math.round((closest.x * 16 - cam.x) * 3),
          sy: Math.round((closest.y * 16 - cam.y) * 3)
        } : null
      };
    });

    // If close enough, stop and click
    if (pos.closest_unnamed && pos.closest_unnamed.sx > 0 && pos.closest_unnamed.sx < 1280 && 
        pos.closest_unnamed.sy > 0 && pos.closest_unnamed.sy < 720) {
      await click(pos.closest_unnamed.sx, pos.closest_unnamed.sy);
      await page.waitForTimeout(3000);
      break;
    }
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return await page.evaluate(() => JSON.stringify(window.__latestGameState.player_position));
}

