    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x, y});
  };

  // Set up MutationObserver for quest panel
  await page.evaluate(() => {
    window._questAccepted2 = false;
    const questPanel = document.getElementById('quest');
    if (questPanel) {
      const observer = new MutationObserver(() => {
        const display = window.getComputedStyle(questPanel).display;
        if (display !== 'none' && !window._questAccepted2) {
          window._questPanelSeen = true;
          console.log('QUEST_PANEL quest=' + (window.game.menu.quest?.activeQuest || 'none'));
          setTimeout(() => {
            const btn = document.getElementById('quest-button');
            if (btn) { btn.click(); window._questAccepted2 = true; }
          }, 200);
        }
      });
      observer.observe(questPanel, { attributes: true, attributeFilter: ['style', 'class'] });
      if (questPanel.parentElement) observer.observe(questPanel.parentElement, { attributes: true });
    }
  });

  // Walk south toward Blacksmith - click lower portion of canvas
  await click(700, 650);
  await page.waitForTimeout(3000);

  // Now click Blacksmith directly using fresh coords
  for (let i = 0; i < 8; i++) {
    const pos = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const bs = gs.nearby_entities.find(e => e.name === 'Blacksmith');
      if (!bs) return null;
      const cam = window.game.camera;
      return { 
        sx: Math.round((bs.x * 16 - cam.x) * 3), 
        sy: Math.round((bs.y * 16 - cam.y) * 3),
        dist: bs.distance
      };
    });
    if (!pos) break;
    const cx = Math.max(50, Math.min(1230, pos.sx));
    const cy = Math.max(50, Math.min(670, pos.sy));
    await click(cx, cy);
    await page.waitForTimeout(1500);
    if (pos.dist <= 2) break;
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const bs = gs.nearby_entities.find(e => e.name === 'Blacksmith');
    return JSON.stringify({
      player_position: gs.player_position,
      blacksmith_dist: bs?.distance,
      quests: gs.quests.filter(q => q.started).map(q => ({key: q.key, stage: q.stage}))
    });
  });
  return state;
}

