async (page) => {
  const getPos = async () => page.evaluate(() => window.__latestGameState.player_position);
  const move = async (key, ms=500) => {
    await page.evaluate(() => { window.game.player.target = null; document.getElementById('canvas').focus(); });
    await page.keyboard.down(key);
    await page.waitForTimeout(ms);
    await page.keyboard.up(key);
    await page.waitForTimeout(150);
  };

  // Get closer to Village Girl at (136, 146)
  for (let i = 0; i < 20; i++) {
    const pos = await getPos();
    const dx = 136 - pos.x;
    const dy = 146 - pos.y;
    if (Math.abs(dx) + Math.abs(dy) <= 3) break;

    // Move in the dominant direction
    if (Math.abs(dx) > Math.abs(dy)) {
      await move(dx < 0 ? 'a' : 'd');
    } else {
      await move(dy < 0 ? 'w' : 's');
    }
  }

  const pos = await getPos();

  // Click Village Girl
  const vgInfo = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const cam = window.game.camera;
    const vg = gs.nearby_entities.find(e => e.name === 'Village Girl');
    if (!vg) return null;
    const sx = Math.round((vg.x * 16 - cam.x) * 3);
    const sy = Math.round((vg.y * 16 - cam.y) * 3);
    return { dist: vg.distance, sx, sy };
  });

  if (vgInfo && vgInfo.dist <= 3) {
    await page.evaluate(({x, y}) => {
      window.game.player.target = null;
      const cx = Math.max(100, Math.min(1180, x));
      const cy = Math.max(80, Math.min(640, y));
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: cx, clientY: cy, bubbles: true }));
    }, { x: vgInfo.sx, y: vgInfo.sy });
    await page.waitForTimeout(2000);
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify({ pos, vgInfo });
}

