async (page) => {
  // Kill more crabs while exploring east along the beach
  const getState = () => page.evaluate(() => {
    const gs = window.__latestGameState;
    const cam = window.game.camera;
    const crabs = gs.nearby_entities.filter(e => e.type === 3 && e.hp > 0 && e.name === 'Crab').sort((a, b) => a.distance - b.distance);
    const drops = gs.nearby_entities.filter(e => e.type === 4).map(d => ({name: d.name, dist: d.distance, cx: d.click_x, cy: d.click_y}));
    const items = gs.nearby_entities.filter(e => e.type !== 3 && e.type !== 10 && e.type !== 12 && e.type !== 0 && e.type !== 1 && e.type !== 4).map(e => ({name: e.name, type: e.type, dist: e.distance}));
    const crab = crabs[0];
    return {
      pos: gs.player_position,
      hp: gs.player_stats.hp, max_hp: gs.player_stats.max_hp,
      level: gs.player_stats.level,
      crab: crab ? {x: crab.x, y: crab.y, dist: crab.distance, sx: Math.round((crab.x * 16 - cam.x) * 3), sy: Math.round((crab.y * 16 - cam.y) * 3)} : null,
      drops, items,
      anvilStage: gs.quests.find(q => q.key === 'anvilsechoes')?.stage
    };
  });

  const clickCanvas = async (x, y) => {
    await page.evaluate(({x, y}) => {
      window.game.player.target = null;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x, y});
  };

  let kills = 0;
  for (let i = 0; i < 10; i++) {
    const s = await getState();
    if (s.drops.length) {
      for (const d of s.drops) {
        await clickCanvas(Math.max(50, Math.min(1230, d.cx)), Math.max(50, Math.min(670, d.cy)));
        await page.waitForTimeout(1500);
      }
    }
    if (s.hp < s.max_hp * 0.35) break;
    if (s.crab) {
      const cx = Math.max(50, Math.min(1230, s.crab.sx));
      const cy = Math.max(50, Math.min(670, s.crab.sy));
      await clickCanvas(cx, cy);
      await page.waitForTimeout(5000);
      kills++;
    } else {
      // Walk east to find more crabs
      await clickCanvas(1100, 380);
      await page.waitForTimeout(2500);
    }
  }

  const s = await getState();
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify({kills, pos: s.pos, level: s.level, hp: s.hp, items: s.items, anvilStage: s.anvilStage});
}

