async (page) => {
  // Get Spooky Skeleton coords
  const skelState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const cam = window.game.camera;
    const skels = (gs.nearby_entities || [])
      .filter(e => e.name === 'Spooky Skeleton' && e.hp > 0)
      .sort((a, b) => a.distance - b.distance);
    const chest = (gs.nearby_entities || [])
      .filter(e => e.type !== 3 && e.type !== 0 && e.type !== 1 && e.type !== 10 && e.type !== 4)
      .slice(0, 5);
    if (!skels[0]) return { skel: null, chest };
    const s = skels[0];
    return {
      skel: { name: s.name, x: s.x, y: s.y, dist: s.distance, hp: s.hp,
        sx: Math.max(50, Math.min(1230, Math.round((s.x * 16 - cam.x) * 3))),
        sy: Math.max(50, Math.min(670, Math.round((s.y * 16 - cam.y) * 3)))
      },
      chest,
      pos: gs.player_position
    };
  });
  console.log('state:', JSON.stringify(skelState));

  if (skelState.skel) {
    // Attack the skeleton
    await page.evaluate(({x, y}) => {
      window.game.player.target = null;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x: skelState.skel.sx, y: skelState.skel.sy});
    await page.waitForTimeout(8000); // Skeletons have 140 HP, takes longer

    const after = await page.evaluate(() => ({
      pos: window.__latestGameState.player_position,
      hp: window.__latestGameState.player_stats.hp,
      level: window.__latestGameState.player_stats.level
    }));
    console.log('after:', JSON.stringify(after));
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify(skelState);
}

